const resp = $.steps.searchMovies.response || {};
const data = resp.data || resp;
const results = data.results || [];

let movieContext = '';
const sources = [];

results.slice(0, 8).forEach((r, i) => {
  const title = r.title || 'Untitled';
  const url = r.url || '';
  const text = (r.text || '').slice(0, 1500);
  movieContext += 'Source ' + (i + 1) + ': ' + title + '\n' + text + '\n\n';
  sources.push({ title, url });
});

return { movieContext, sources, sourceCount: results.length };

const query = $.input.query;
const maxRecs = $.input.maxRecommendations || 5;
const movieData = $.steps.parseMovieData.output;

let prompt = 'You are a passionate cinephile and movie recommendation expert. Use the research data to provide personalized movie recommendations.\n\n';
prompt += 'USER REQUEST: ' + query + '\n';
prompt += 'NUMBER OF RECOMMENDATIONS: ' + maxRecs + '\n\n';
prompt += 'MOVIE DATA FROM SEARCH:\n' + movieData.movieContext + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Recommend exactly ' + maxRecs + ' movies that match the request\n';
prompt += '- For each movie, explain WHY it matches what the user wants\n';
prompt += '- Include movie year, genre, director, and a brief plot (no spoilers!)\n';
prompt += '- Rate how well each movie matches the request (1-5 stars)\n';
prompt += '- Include a "watch if you like" note for each\n';
prompt += '- Order by best match first\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "recommendations": [\n';
prompt += '    {\n';
prompt += '      "title": "Movie Title",\n';
prompt += '      "year": 2024,\n';
prompt += '      "genre": "Genre",\n';
prompt += '      "director": "Director Name",\n';
prompt += '      "matchRating": 5,\n';
prompt += '      "whyWatch": "Why this matches your request",\n';
prompt += '      "plotTeaser": "Brief non-spoiler plot description",\n';
prompt += '      "watchIfYouLike": "Similar movies/shows"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "userPreferenceSummary": "What we understood you want",\n';
prompt += '  "bonusPick": "One surprise wildcard recommendation with reason"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiRecommend.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { recommendations: [], userPreferenceSummary: raw, bonusPick: '' }; }

const ai = $.steps.parseAI.output;
const query = $.input.query;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Movie Recommendations', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Your request:* ' + query } });

if (ai.userPreferenceSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':mag: _' + ai.userPreferenceSummary + '_' } });
}
blocks.push({ type: 'divider' });

if (ai.recommendations && ai.recommendations.length > 0) {
  ai.recommendations.forEach((rec, i) => {
    const stars = ':star:'.repeat(Math.min(rec.matchRating || 0, 5));
    let text = '*' + (i + 1) + '. ' + (rec.title || 'Unknown') + '* (' + (rec.year || 'N/A') + ')';
    text += '\n:movie_camera: ' + (rec.genre || 'N/A') + ' | :clapper: ' + (rec.director || 'Unknown');
    text += '\n' + stars;
    text += '\n\n' + (rec.plotTeaser || '').slice(0, 300);
    text += '\n\n:point_right: *Why:* ' + (rec.whyWatch || '').slice(0, 200);
    if (rec.watchIfYouLike) {
      text += '\n:heart: Watch if you like: _' + rec.watchIfYouLike + '_';
    }
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 2000) } });
    if (i < ai.recommendations.length - 1) {
      blocks.push({ type: 'divider' });
    }
  });
}

if (ai.bonusPick) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':gift: *Bonus Wildcard Pick:*\n' + ai.bonusPick } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Search + Claude AI + One CLI' }] });

const titles = (ai.recommendations || []).slice(0, 3).map(r => r.title).join(', ');
const fallback = 'Movie Recs: ' + titles;
return { blocks, fallback };
